            language: "ja",
            name: "\uFF5E\u305B\u308B\u30FB\u3055\u305B\u308B",
            description: "\u3060\u308C\u304B\u306B\u3042\u308B\u884C\u70BA\u3092\u3055\u305B\u308B\u610F\u3092\u8868\u308F\u3059\u6642\u306E\u8A00\u3044\u65B9\u3002\u4F8B\u3001\u300C\u884C\u304B\u305B\u308B\u300D\u306E\u300C\u305B\u308B\u300D\u3002"
