            name: "\uFF5E\u3059\u30FB\u3055\u3059",
            description: "\u3060\u308C\u304B\u306B\u3042\u308B\u884C\u70BA\u3092\u3055\u305B\u308B\u610F\u3092\u8868\u308F\u3059\u6642\u306E\u8A00\u3044\u65B9\u3002\u4F8B\u3001\u300C\u98DF\u3079\u3055\u3059\u300D\u306E\u300C\u3055\u3059\u300D\u3002"
