            language: "ja",
            name: "\uFF5E\u3052",
            description: "\u2026\u3067\u3042\u308A\u305D\u3046\u306A\u69D8\u5B50\u3002\u3044\u304B\u306B\u3082\u2026\u3089\u3057\u3044\u3055\u307E\u3002"
